	(3569, 'PARAGRAPH', '{"type":"paragraph","text":"Este grupo hidráulico ha sido diseñado con el objetivo de constituir una unidad autónoma y económica, de suministro de energía hidráulica.","json":{"type":"paragraph","attrs":{"blockId":"block_3c8y8ko","backendId":3569},"content":[{"type":"text","text":"Este grupo hidráulico ha sido diseñado con el objetivo de constituir una unidad autónoma y económica, de suministro de energía hidráulica."}]}}', 'Este grupo hidráulico ha sido diseñado con el objetivo de constituir una unidad autónoma y económica, de suministro de energía hidráulica.', NULL, NULL, NULL, '2026-06-26 11:45:45.470340', 'ES', 2, '2026-06-26 12:04:28.092546', 508);
