	(3721, 'PARAGRAPH', '{"type":"paragraph","text":"Para vaciar totalmente el depósito de agua, tirar de la válvula de vaciado para sacarla de las pinzas de anclaje, colocarla en el sumidero del laboratorio y abrirla.","json":{"type":"paragraph","attrs":{"blockId":"block_gsxdbbd","backendId":3721},"content":[{"type":"text","text":"Para vaciar totalmente el depósito de agua, tirar de la válvula de vaciado para sacarla de las pinzas de anclaje, colocarla en el sumidero del laboratorio y abrirla."}]}}', 'Para vaciar totalmente el depósito de agua, tirar de la válvula de vaciado para sacarla de las pinzas de anclaje, colocarla en el sumidero del laboratorio y abrirla.', NULL, NULL, NULL, '2026-06-26 12:17:23.974141', 'ES', 56, '2026-06-26 12:59:21.370416', 510);
