INSERT INTO `reusable_fragments` (`id`, `code`, `title`, `description`, `product_category`, `product_codes`, `content_json`, `active`, `created_at`, `updated_at`) VALUES
	(6, 'FRG-004', 'Lo que se repite', NULL, NULL, NULL, '{"type":"FRAGMENT","titleEs":"Lo que se repite","titleEn":"Lo que se repite","blocks":[{"id":0,"sortOrder":1,"blockType":"HEADING","languageCode":"ES","contentJson":"{\\"type\\":\\"heading\\",\\"text\\":\\"Descripción\\",\\"level\\":1,\\"json\\":{\\"type\\":\\"heading\\",\\"attrs\\":{\\"blockId\\":\\"block_i5gpw7m\\",\\"backendId\\":3321,\\"level\\":1},\\"content\\":[{\\"type\\":\\"text\\",\\"text\\":\\"Descripción\\"}]}}","plainText":"Descripción"},{"id":1,"sortOrder":1,"blockType":"HEADING","languageCode":"EN","contentJson":"{\\"type\\":\\"heading\\",\\"text\\":\\"Description\\",\\"level\\":1,\\"json\\":{\\"type\\":\\"heading\\",\\"attrs\\":{\\"blockId\\":\\"block_h2nx4bc\\",\\"backendId\\":1,\\"level\\":1},\\"content\\":[{\\"type\\":\\"text\\",\\"text\\":\\"Description\\"}]}}","plainText":"Description"},{"id":2,"sortOrder":2,"blockType":"PARAGRAPH","languageCode":"ES","contentJson":"{\\"type\\":\\"paragraph\\",\\"text\\":\\"El equipo está pensado para trabajar junto al banco hidráulico (FL01.4, FL01.5 o FL 01.6), pero para facilitar el manejo y el poder conseguir el flujo laminar, se aconseja colocarlo sobre una superficie plana, para que las vibraciones del banco no afecten al equipo.\\",\\"json\\":{\\"type\\":\\"paragraph\\",\\"attrs\\":{\\"blockId\\":\\"block_30f7l8b\\",\\"backendId\\":3322},\\"content\\":[{\\"type\\":\\"text\\",\\"text\\":\\"El equipo está pensado para trabajar junto al banco hidráulico (FL01.4, FL01.5 o FL 01.6), pero para facilitar el manejo y el poder conseguir el flujo laminar, se aconseja colocarlo sobre una superficie plana, para que las vibraciones del banco no afecten al equipo.\\"}]}}","plainText":"El equipo está pensado para trabajar junto al banco hidráulico (FL01.4, FL01.5 o FL 01.6), pero para facilitar el manejo y el poder conseguir el flujo laminar, se aconseja colocarlo sobre una superficie plana, para que las vibraciones del banco no afecten al equipo."},{"id":3,"sortOrder":2,"blockType":"PARAGRAPH","languageCode":"EN","contentJson":"{\\"type\\":\\"paragraph\\",\\"text\\":\\"El equipo está pensado para trabajar junto al banco hidráulico (FL01.4, FL01.5 o FL 01.6), pero para facilitar el manejo y el poder conseguir el flujo laminar, se aconseja colocarlo sobre una superficie plana, para que las vibraciones del banco no afecten al equipo.\\",\\"json\\":{\\"type\\":\\"paragraph\\",\\"attrs\\":{\\"blockId\\":\\"block_spjgvml\\",\\"backendId\\":3},\\"content\\":[{\\"type\\":\\"text\\",\\"text\\":\\"El equipo está pensado para trabajar junto al banco hidráulico (FL01.4, FL01.5 o FL 01.6), pero para facilitar el manejo y el poder conseguir el flujo laminar, se aconseja colocarlo sobre una superficie plana, para que las vibraciones del banco no afecten al equipo.\\"}]}}","plainText":"El equipo está pensado para trabajar junto al banco hidráulico (FL01.4, FL01.5 o FL 01.6), pero para facilitar el manejo y el poder conseguir el flujo laminar, se aconseja colocarlo sobre una superficie plana, para que las vibraciones del banco no afecten al equipo."},{"id":4,"sortOrder":3,"blockType":"PARAGRAPH","languageCode":"ES","contentJson":"{\\"type\\":\\"paragraph\\",\\"text\\":\\"A través del tubo de vidrio que dispone el equipo, hacemos pasar un flujo de agua, junto con tinta dosificada por una aguja, a la entrada del conducto.\\",\\"json\\":{\\"type\\":\\"paragraph\\",\\"attrs\\":{\\"blockId\\":\\"block_vg0femt\\",\\"backendId\\":3323},\\"content\\":[{\\"type\\":\\"text\\",\\"text\\":\\"A través del tubo de vidrio que dispone el equipo, hacemos pasar un flujo de agua, junto con tinta dosificada por una aguja, a la entrada del conducto.\\"}]}}","plainText":"A través del tubo de vidrio que dispone el equipo, hacemos pasar un flujo de agua, junto con tinta dosificada por una aguja, a la entrada del conducto."},{"id":5,"sortOrder":3,"blockType":"PARAGRAPH","languageCode":"EN","contentJson":"{\\"type\\":\\"paragraph\\",\\"text\\":\\"A través del tubo de vidrio que dispone el equipo, hacemos pasar un flujo de agua, junto con tinta dosificada por una aguja, a la entrada del conducto.\\",\\"json\\":{\\"type\\":\\"paragraph\\",\\"attrs\\":{\\"blockId\\":\\"block_457y251\\",\\"backendId\\":5},\\"content\\":[{\\"type\\":\\"text\\",\\"text\\":\\"A través del tubo de vidrio que dispone el equipo, hacemos pasar un flujo de agua, junto con tinta dosificada por una aguja, a la entrada del conducto.\\"}]}}","plainText":"A través del tubo de vidrio que dispone el equipo, hacemos pasar un flujo de agua, junto con tinta dosificada por una aguja, a la entrada del conducto."},{"id":6,"sortOrder":4,"blockType":"PARAGRAPH","languageCode":"ES","contentJson":"{\\"type\\":\\"paragraph\\",\\"text\\":\\"En función del caudal que pasa por este tubo, se puede ver claramente como la tinta se mezcla o no con el agua, formando una línea de corriente claramente visualizable en casos de régimen laminar, o podremos visualizar cómo la tinta se va mezclando con el agua en regímenes de transición. Una vez alcanzado el régimen turbulento, la tinta estará completamente mezclada con el agua, y no se podrá distinguir.\\",\\"json\\":{\\"type\\":\\"paragraph\\",\\"attrs\\":{\\"blockId\\":\\"block_if0ka60\\",\\"backendId\\":3324},\\"content\\":[{\\"type\\":\\"text\\",\\"text\\":\\"En función del caudal que pasa por este tubo, se puede ver claramente como la tinta se mezcla o no con el agua, formando una línea de corriente claramente visualizable en casos de régimen laminar, o podremos visualizar cómo la tinta se va mezclando con el agua en regímenes de transición. Una vez alcanzado el régimen turbulento, la tinta estará completamente mezclada con el agua, y no se podrá distinguir.\\"}]}}","plainText":"En función del caudal que pasa por este tubo, se puede ver claramente como la tinta se mezcla o no con el agua, formando una línea de corriente claramente visualizable en casos de régimen laminar, o podremos visualizar cómo la tinta se va mezclando con el agua en regímenes de transición. Una vez alcanzado el régimen turbulento, la tinta estará completamente mezclada con el agua, y no se podrá distinguir."},{"id":7,"sortOrder":4,"blockType":"PARAGRAPH","languageCode":"EN","contentJson":"{\\"type\\":\\"paragraph\\",\\"text\\":\\"En función del caudal que pasa por este tubo, se puede ver claramente como la tinta se mezcla o no con el agua, formando una línea de corriente claramente visualizable en casos de régimen laminar, o podremos visualizar cómo la tinta se va mezclando con el agua en regímenes de transición. Una vez alcanzado el régimen turbulento, la tinta estará completamente mezclada con el agua, y no se podrá distinguir.\\",\\"json\\":{\\"type\\":\\"paragraph\\",\\"attrs\\":{\\"blockId\\":\\"block_czjd1zh\\",\\"backendId\\":7},\\"content\\":[{\\"type\\":\\"text\\",\\"text\\":\\"En función del caudal que pasa por este tubo, se puede ver claramente como la tinta se mezcla o no con el agua, formando una línea de corriente claramente visualizable en casos de régimen laminar, o podremos visualizar cómo la tinta se va mezclando con el agua en regímenes de transición. Una vez alcanzado el régimen turbulento, la tinta estará completamente mezclada con el agua, y no se podrá distinguir.\\"}]}}","plainText":"En función del caudal que pasa por este tubo, se puede ver claramente como la tinta se mezcla o no con el agua, formando una línea de corriente claramente visualizable en casos de régimen laminar, o podremos visualizar cómo la tinta se va mezclando con el agua en regímenes de transición. Una vez alcanzado el régimen turbulento, la tinta estará completamente mezclada con el agua, y no se podrá distinguir."}]}', 1, '2026-06-25 11:44:02', '2026-06-25 11:44:30');
